SELECT
	HOMEPAGE_ID, QUIZ_IDX, QUIZ_TYPE, QUIZ_NAME, QUIZ_YEAR, QUIZ_MONTH, BOOK_NAME, BOOK_AUTHOR, BOOK_PUBLISHER,
	CALL_NO, BOOK_DESC, QUIZ_START_DATE, QUIZ_END_DATE, IMG_FILE_NAME, REAL_FILE_NAME, FILE_EXTENSION, FILE_SIZE,
	TOP_HTML, BOTTOM_HTML, DELETE_YN, ADD_DATE, ADD_ID, MOD_DATE, MOD_ID, SCHOOL_YN, BAN_YN, HAK_YN,
	(SELECT COUNT(*) FROM QUIZ_REQ WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND QUIZ_IDX = a.QUIZ_IDX) AS QUIZ_REQ_COUNT,
	SELECT_CNT, QUIZ_RESULT_DATE, BOOK_LINK, QUIZ_NOTICE
FROM
	QUIZ a
WHERE HOMEPAGE_ID = #{homepage_id} 
	AND QUIZ_YEAR = #{quiz_year} 
	AND QUIZ_MONTH = #{quiz_month}
	AND QUIZ_TYPE = #{quiz_type} 
	AND DELETE_YN = 'N'

